body:
cc @seldridge 

After #8405 was merged, there was a regression in SystemVerilog emission from FIRRTL for designs containing layers. Many intermediate signals, which previously had meaningful names, were replaced with `_layer_probe_*` signals.

I came up with a somewhat-minimal design which generates some interesting intermediate signals, which get nicely named in the output SystemVerilog. Then when you introduce a layer, the naming is degraded. Here is a Chisel design for recreating that condition:

```scala
//> using scala 2.13.16
//> using repository https://s01.oss.sonatype.org/content/repositories/snapshots
//> using dep org.chipsalliance::chisel:7.0.0-RC1+8-81480282-SNAPSHOT
//> using plugin org.chipsalliance:::chisel-plugin:7.0.0-RC1+8-81480282-SNAPSHOT
//> using options -unchecked -deprecation -language:reflectiveCalls -feature -Xcheckinit -Xfatal-warnings -Ywarn-dead-code -Ywarn-unused -Ymacro-annotations

// Replace the SNAPSHOT above with these to use firtool-1.114.1, which doesn't include #8405
// //> using dep org.chipsalliance::chisel:7.0.0-RC1+4-fe547683-SNAPSHOT
// //> using plugin org.chipsalliance:::chisel-plugin:7.0.0-RC1+4-fe547683-SNAPSHOT

import chisel3._
import chisel3.util._

class Foo extends Module {
  val in = IO(Flipped(Decoupled(UInt(4.W))))
  val out = IO(Decoupled(UInt(4.W)))

  val foo = RegInit(0.U(8.W))
  foo :<= foo + 1.U

  val qs = Seq.fill(2)(Module(new Queue(UInt(4.W), 8)))

  val allQsReady = qs.map(_.io.enq.ready).reduce(_ && _)
  val enqFire    = in.valid && allQsReady && (foo === 0xff.U)

  in.ready :<= enqFire
  qs.foreach(_.io.enq.valid :<= enqFire)
  qs.foreach(_.io.enq.bits :<= in.bits)

  val allQsValid = qs.map(_.io.deq.valid).reduce(_ && _)
  val deqFire = out.ready && allQsValid && (foo === 0.U)

  out.valid :<= deqFire
  qs.foreach(_.io.deq.ready :<= deqFire)

  out.bits :<= qs.map(_.io.deq.bits).reduce(_ | _)

  // Uncomment to experiment with how `enqFire` gets named
  // when(enqFire) {
  //   printf("enqFire\n")
  // }
}

object Main extends App {
  import _root_.circt.stage.ChiselStage
  println(
    ChiselStage.emitSystemVerilog(
      new Foo,
      firtoolOpts = Array("-disable-all-randomization", "-strip-debug-info")
    )
  )
}
```

When you run this, you get this output, which notably has the signal named `enqFire`:

```verilog
// Generated by CIRCT firtool-1.116.0
// VCS coverage exclude_file

// RAM and queue modules ...

module Foo(
  input        clock,
               reset,
  output       in_ready,
  input        in_valid,
  input  [3:0] in_bits,
  input        out_ready,
  output       out_valid,
  output [3:0] out_bits
);

  wire       _qs_1_io_enq_ready;
  wire       _qs_1_io_deq_valid;
  wire [3:0] _qs_1_io_deq_bits;
  wire       _qs_0_io_enq_ready;
  wire       _qs_0_io_deq_valid;
  wire [3:0] _qs_0_io_deq_bits;
  reg  [7:0] foo;
  wire       enqFire = in_valid & _qs_0_io_enq_ready & _qs_1_io_enq_ready & (&foo);
  wire       deqFire = out_ready & _qs_0_io_deq_valid & _qs_1_io_deq_valid & foo == 8'h0;
  always @(posedge clock) begin
    if (reset)
      foo <= 8'h0;
    else
      foo <= foo + 8'h1;
  end // always @(posedge)
  Queue8_UInt4 qs_0 (
    .clock        (clock),
    .reset        (reset),
    .io_enq_ready (_qs_0_io_enq_ready),
    .io_enq_valid (enqFire),
    .io_enq_bits  (in_bits),
    .io_deq_ready (deqFire),
    .io_deq_valid (_qs_0_io_deq_valid),
    .io_deq_bits  (_qs_0_io_deq_bits)
  );
  Queue8_UInt4 qs_1 (
    .clock        (clock),
    .reset        (reset),
    .io_enq_ready (_qs_1_io_enq_ready),
    .io_enq_valid (enqFire),
    .io_enq_bits  (in_bits),
    .io_deq_ready (deqFire),
    .io_deq_valid (_qs_1_io_deq_valid),
    .io_deq_bits  (_qs_1_io_deq_bits)
  );
  assign in_ready = enqFire;
  assign out_valid = deqFire;
  assign out_bits = _qs_0_io_deq_bits | _qs_1_io_deq_bits;
endmodule
```

If you uncomment that `printf` statement, you get this layer module:

```verilog
// ----- 8< ----- FILE "verification/Foo_Verification.sv" ----- 8< -----

// Generated by CIRCT firtool-1.116.0

// Users can define 'PRINTF_COND' to add an extra gate to prints.
`ifndef PRINTF_COND_
  `ifdef PRINTF_COND
    `define PRINTF_COND_ (`PRINTF_COND)
  `else  // PRINTF_COND
    `define PRINTF_COND_ 1
  `endif // PRINTF_COND
`endif // not def PRINTF_COND_
module Foo_Verification();
  `ifndef SYNTHESIS
    always @(posedge Foo.clock) begin
      if ((`PRINTF_COND_) & Foo._layer_probe & ~Foo.reset)
        $fwrite(32'h80000002, "enqFire\n");
    end // always @(posedge)
  `endif // not def SYNTHESIS
endmodule
```

And you get the following diff in the `Foo` module:

```diff
--- Foo.without-layer.v 2025-05-05 11:14:44
+++ Foo.with-layer.v    2025-05-05 11:15:13
@@ -16,7 +16,7 @@
   wire       _qs_0_io_deq_valid;
   wire [3:0] _qs_0_io_deq_bits;
   reg  [7:0] foo;
-  wire       enqFire = in_valid & _qs_0_io_enq_ready & _qs_1_io_enq_ready & (&foo);
+  wire       _layer_probe = in_valid & _qs_0_io_enq_ready & _qs_1_io_enq_ready & (&foo);
   wire       deqFire = out_ready & _qs_0_io_deq_valid & _qs_1_io_deq_valid & foo == 8'h0;
   always @(posedge clock) begin
     if (reset)
@@ -28,7 +28,7 @@
     .clock        (clock),
     .reset        (reset),
     .io_enq_ready (_qs_0_io_enq_ready),
-    .io_enq_valid (enqFire),
+    .io_enq_valid (_layer_probe),
     .io_enq_bits  (in_bits),
     .io_deq_ready (deqFire),
     .io_deq_valid (_qs_0_io_deq_valid),
@@ -38,13 +38,13 @@
     .clock        (clock),
     .reset        (reset),
     .io_enq_ready (_qs_1_io_enq_ready),
-    .io_enq_valid (enqFire),
+    .io_enq_valid (_layer_probe),
     .io_enq_bits  (in_bits),
     .io_deq_ready (deqFire),
     .io_deq_valid (_qs_1_io_deq_valid),
     .io_deq_bits  (_qs_1_io_deq_bits)
   );
-  assign in_ready = enqFire;
+  assign in_ready = _layer_probe;
   assign out_valid = deqFire;
   assign out_bits = _qs_0_io_deq_bits | _qs_1_io_deq_bits;
 endmodule
```

So the `enqFire` signal gets replaced with `_layer_probe`. If you run this design with `firtool-1.114.1` (see comments in the sample above to perform that experiment), then `enqFire`'s name is retained in the design that includes the `printf`.

